+    st = asx_canonical_fixture_validate(&parsed);
+    if (st != ASX_OK) {
+        goto fail;
+    }
+
+    *out_fixture = parsed;
+    return ASX_OK;
+
+fail:
+    asx_canonical_fixture_reset(&parsed);
+    return st;
+}
