+        return st;
+    }
+    if (strcmp(fixture->fixture_schema_version, "fixture-v1") != 0) {
+        return ASX_E_INVALID_ARGUMENT;
+    }
+
+    out_payload->len = 0u;
+    if (out_payload->data != NULL) {
+        out_payload->data[0] = '\0';
+    }
